mainPlayer.on('play', function() { $('.quality_change').fadeOut(); });

mainPlayer.on('pause', function() { $('.quality_change').fadeIn(); });

$('.hd_btn').on('click', function() {

	var link = $(this).attr('data-url'),

		postime = mainPlayer.getPosition();

	$('.hd_btn').removeClass('selected');

	$(this).addClass('selected');

	mainPlayer.load([{'file': link}]);

	mainPlayer.play();

	mainPlayer.on('firstFrame', function() { mainPlayer.seek(postime); });

});

$('.go_10sec').on('click', function() {

	var pos = mainPlayer.getPosition()+10;

	mainPlayer.play();

	mainPlayer.seek(pos);

});

$('.back_10sec').on('click', function() {

	var pos = mainPlayer.getPosition()-10;

	if (pos < 0) {var pos = 0;};

	mainPlayer.play();

	mainPlayer.seek(pos);

});

		

